route_list route.h定义了几个函数分别用来获取、查找、新增route
// src/core/route.h int route_get(struct route_list *rt, char *name); int route_lookup(struct route_list *rt, char *name); void push(struct action *a, struct action **head); struct route_list { struct action **rlist; int idx;	/* first empty entry */ int entries;	/* total number of entries */ struct str_hash_table names; /* name to route index mappings */ }; rlist 我们对route_list数据模型进行简化:
rlist是一个固定长度的一维数组，通过索引来访问对应的值。如果数组的空间不足，那么就创建一个两倍大的空数据，然后先把原始数据复制过去。这种复制方式保持的原始数据的索引位置。有点像golang的切片扩容机制。
这里最为重要的就是保持数组元素的索引位置在扩容后不变。
static inline int route_new_list(struct route_list *rt) { int ret; struct action **tmp; ret = -1; if(rt-&gt;idx &gt;= rt-&gt;entries) { // 两倍扩容 tmp = pkg_realloc(rt-&gt;rlist, 2 * rt-&gt;entries * sizeof(struct action *)); if(tmp == 0) { LM_CRIT(&#34;out of memory\n&#34;); goto end; } /* init the newly allocated memory chunk */ memset(&amp;tmp[rt-&gt;entries], 0, rt-&gt;entries * sizeof(struct action *)); rt-&gt;rlist = tmp; rt-&gt;entries *= 2; } if(rt-&gt;idx &lt; rt-&gt;entries) { ret = rt-&gt;idx; rt-&gt;idx++; } end: return ret; } str_hash_table 我们对hash_table的数据模型进行简化，它其实就是一hash表，key是路由的名，值是一个正数，正数代表了路由执行单元的索引位置。
如果我们用js对route_list来表示
dispatcher:dst-down对应的是索引0 索引0在rlist里对应的是func1 dispatcher:dst-down事件发生后，调用func1 let rlist = [func1, func2, func3] let names = { &#39;dispatcher:dst-down&#39;: 0, &#39;rtpengine:dtmf-event&#39;: 1 } 其实这里完全可以不用数组，如果在js里, 可以直接用函数作为hash的key
let names = { &#39;dispatcher:dst-down&#39;: func1, &#39;rtpengine:dtmf-event&#39;: func2 } action // src/core/route_struct.h struct action { int cline; char *cfile; char *rname; enum action_type type; /* forward, drop, log, send ...*/ int count; struct action *next; action_u_t val[MAX_ACTIONS]; }; str_hash_table struct str_hash_table { struct str_hash_head *table; int size; }; struct str_hash_head { struct str_hash_entry *next; struct str_hash_entry *prev; }; struct str_hash_entry { struct str_hash_entry *next; struct str_hash_entry *prev; str key; unsigned int flags; union { void *p; char *s; int n; char data[sizeof(void *)]; } u; }; 在src/core/route.c中定义如下几个变量，分别管理着6钟不同的路由。
