${err.stack}`) server.close() }) server.on(&#39;message&#39;, (msg, rinfo) =&gt; { logger.info(`${process.pid} udp server got: ${msg} from ${rinfo.address}:${rinfo.port}`) }) server.on(&#39;listening&#39;, () =&gt; { const address = server.address() logger.info(`udp server listening ${address.address}:${address.port}`) }) server.bind(port) } 日志库如下：
