cluster模块实际上是一个事件发射器 cluster模块有两种负载均衡方式 SCHED_NONE 由操作系统决定 SCHED_RR 轮询的方式 const { ArrayPrototypePush, ArrayPrototypeSlice, ArrayPrototypeSome, ObjectKeys, ObjectValues, RegExpPrototypeTest, SafeMap, StringPrototypeStartsWith, } = primordials; const assert = require(&#39;internal/assert&#39;); const { fork } = require(&#39;child_process&#39;); const path = require(&#39;path&#39;); const EventEmitter = require(&#39;events&#39;); const RoundRobinHandle = require(&#39;internal/cluster/round_robin_handle&#39;); const SharedHandle = require(&#39;internal/cluster/shared_handle&#39;); const Worker = require(&#39;internal/cluster/worker&#39;); const { internal, sendHelper } = require(&#39;internal/cluster/utils&#39;); const cluster = new EventEmitter(); const intercom = new EventEmitter(); const SCHED_NONE = 1; const SCHED_RR = 2; const minPort = 1024; const maxPort = 65535; const { validatePort } = require(&#39;internal/validators&#39;); module.exports = cluster; const handles = new SafeMap(); cluster.isWorker = false; cluster.isMaster = true; // Deprecated alias. Must be same as isPrimary. cluster.isPrimary = true; cluster.Worker = Worker; cluster.workers = {}; cluster.settings = {}; cluster.SCHED_NONE = SCHED_NONE; // Leave it to the operating system. cluster.SCHED_RR = SCHED_RR; // Primary distributes connections. 轮询策略如何选择 接下来，我们就要再看看，两种不同的负载策略是如何选择的？
负载策略刚开始来自NODE_CLUSTER_SCHED_POLICY这个环境变量 这个环境变量有两个值 rr和none 但是如果系统平台是win32, 也就是windows的情况下，则不会使用轮训的负载方式 除此以外，默认将会使用轮训的负载方式 // XXX(bnoordhuis) Fold cluster.schedulingPolicy into cluster.settings? let schedulingPolicy = process.env.NODE_CLUSTER_SCHED_POLICY; if (schedulingPolicy === &#39;rr&#39;) schedulingPolicy = SCHED_RR; else if (schedulingPolicy === &#39;none&#39;) schedulingPolicy = SCHED_NONE; else if (process.platform === &#39;win32&#39;) { // Round-robin doesn&#39;t perform well on // Windows due to the way IOCP is wired up. schedulingPolicy = SCHED_NONE; } else schedulingPolicy = SCHED_RR; cluster.schedulingPolicy = schedulingPolicy; 那么，为什么udp的多进程服务器，并没有做到轮询的负载呢？
轮询策略的使用 即使调用策略是轮询的方式，如果socker是udp的，也不会用轮训的方式去处理，而用SharedHandle去处理 注释里面写，udp使用轮询的方式是无意义的，这点我不太理解 // UDP is exempt from round-robin connection balancing for what should // be obvious reasons: it&#39;s connectionless. There is nothing to send to // the workers except raw datagrams and that&#39;s pointless. if (schedulingPolicy !== SCHED_RR || message.addressType === &#39;udp4&#39; || message.addressType === &#39;udp6&#39;) { handle = new SharedHandle(key, address, message); } else { handle = new RoundRobinHandle(key, address, message); }

假如一个模块暴露了一个函数，叫做do_something(), 仅支持传递一个参数。这个函数在c文件中对应w_do_something()
// 在opensips.cfg文件中 route{ do_something(&#34;abc&#34;) } static int w_do_something(struct sip_msg* msg, char* str1){ // 在c文件中，我们打印str1的值，这个字符串就是abc } // 在opensips.cfg文件中 route{ $var(num)=&#34;abc&#34;; do_something(&#34;$var(num)&#34;) } static int w_do_something(struct sip_msg* msg, char* str1){ // 在c文件中，我们打印str1的值，这个字符串就是$var(num) // 这时候就有问题了，其实我们想获取的是$var(num)的值abc, 而不是字符串$var(num) } 那怎么获取$var()的传参的值呢？这里就需要用到了函数的fixup_函数。
static cmd_export_t cmds[]={ {&#34;find_zone_code&#34;, (cmd_function)w_do_something, 2, fixup_do_something, 0, REQUEST_ROUTE}, {0,0,0,0,0,0} }; // 调用fixup_spve， 只有在fixup函数中，对函数的参数执行了fixup, 在真正的执行函数中，才能得到真正的$var()的值 static int fixup_do_something(void** param, int param_no) { LM_INFO(&#34;fixup_find_zone_code: param: %s param_no: %d
&#34;, (char *)*param, param_no); return fixup_spve(param); } static int w_do_something (struct sip_msg* msg, char* str1){ str zone; if (fixup_get_svalue(msg, (gparam_p)str1, &amp;zone) != 0) { LM_WARN(&#34;cannot find the phone!
&#34;); return -1; } LM_INFO(&#34;zone:%s
&#34;, zone.s); return 1; }

